Para encontrar el divisor primo más pequeño de un número, podemos utilizar una función que compruebe si un número es primo y luego busque el primer divisor primo de ese número.

```python
def es_primo(n):
    # Si n es menor que 2, no es primo
    if n < 2:
        return False
    # Comprobamos si n es divisible por cualquier número desde 2 hasta la raíz cuadrada de n
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    # Si no encontramos ningún divisor, n es primo
    return True

def primer_divisor(n):
    # Comenzamos a buscar divisores desde 2
    divisor = 2
    # Mientras que n sea mayor que 1
    while n > 1:
        # Si n es divisible por divisor, entonces divisor es un divisor de n
        if n % divisor == 0:
            # Comprobamos si divisor es primo
            if es_primo(divisor):
                # Si es primo, entonces es el divisor primo más pequeño de n
                return divisor
        # Si n no es divisible por divisor, pasamos a buscar el siguiente número
        divisor += 1

def smallest_Divisor(n):
    # Si n es primo, entonces su divisor primo más pequeño es n mismo
    if es_primo(n):
        return n
    # Si n no es primo, buscamos su primer divisor primo
    else:
        return primer_divisor(n)
```

