```python
def kth_element(arr, k):
    if k < 1:
        raise ValueError("Índice inválido")
    if not arr:
        raise ValueError("Lista vacía")
    if k <= len(arr):
        return arr[k - 1]
    raise ValueError("Índice fuera de rango")
    if not isinstance(k, int):
        raise TypeError("Índice no es un número entero")
    if len(arr) == 1:
        return arr[0]
    mid = len(arr) // 2
    if k <= mid + 1:
        return kth_element(arr[:mid], k)
    else:
        return kth_element(arr[mid + 1:], k - mid - 1)
