```python
def first_non_repeating_character(s):
    # Creamos un diccionario para almacenar la frecuencia de cada carácter
    char_frequency = {}

    # Recorremos la cadena para contar la frecuencia de cada carácter
    for char in s:
        # Si el carácter ya está en el diccionario, incrementamos su frecuencia
        if char in char_frequency:
            char_frequency[char] += 1
        # Si el carácter no está en el diccionario, lo agregamos con una frecuencia de 1
        else:
            char_frequency[char] = 1

    # Recorremos la cadena nuevamente para encontrar el primer carácter no repetido
    for char in s:
        # Si el carácter tiene una frecuencia de 1, lo devolvemos inmediatamente
        if char_frequency[char] == 1:
            return char

    # Si no encontramos ningún carácter no repetido, devolvemos None
    return None
```

