```python
def last_Two_Digits(n):
    # Si el número es menor que 10, simplemente regresamos el factorial del número
    if n < 10:
        return factorial(n)

    # Calculamos los últimos dos dígitos del factorial de n
    last_two_digits = 1
    for i in range(1, n + 1):
        # Calculamos el factorial de i y lo multiplicamos con los últimos dos dígitos actuales
        last_two_digits = (last_two_digits * factorial(i)) % 100

    # Regresamos los últimos dos dígitos
    return last_two_digits

# Función factorial
