import heapq
from collections import Counter

def func(nums):
    # Contamos la frecuencia de cada número en las listas de enteros
    freq = Counter(num for lst in nums for num in lst)

    # Creamos una pila de prioridades para almacenar los números más frecuentes
    heap = []

    # Iteramos sobre los números y su frecuencia
    for num, count in freq.items():
        # Si la pila de prioridades tiene menos de k elementos, lo agregamos
        if len(heap) < k:
            heapq.heappush(heap, (-count, num))
        # Si la pila de prioridades tiene k elementos y el número actual tiene una frecuencia mayor que el número en la cima de la pila, lo reemplazamos
        elif -count > heap[0][0]:
            heapq.heappop(heap)
            heapq.heappush(heap, (-count, num))

    # Devolvemos los k números más frecuentes
    return [num for _, num in heap]

