        # Si hemos procesado todos los bits de la primera mitad y la suma no es igual a la suma de la segunda mitad, devolvemos la suma de los casos en los que el bit actual de la primera mitad es 0 y 1
        if i < n and j < n:
            return dp(i + 1, j, n) + dp(i, j + 1, n)
        # Si hemos procesado todos los bits de la segunda mitad y la suma no es igual a la suma de la primera mitad, devolvemos la suma de los casos en los que el bit actual de la segunda mitad es 0 y 1
        if i < n and j >= n:
            return dp(i + 1, j, n) + dp(i, j, n)
        # Si hemos procesado todos los bits de la primera mitad y la suma es igual a la suma de la segunda mitad, devolvemos la suma de los casos en los que el bit actual de la primera mitad es 0 y 1
        if i >= n and j < n:
            return dp(i, j + 1, n) + dp(i, j, n)
        # Si hemos procesado todos los bits de la primera mitad y la suma es igual a la suma de la segunda mitad, devolvemos la suma de los casos en los que el bit actual de la primera mitad es 0 y 1
        if i >= n and j >= n:
            return dp(i, j, n) + dp(i, j, n)

